    void genCadreSheet(HSSFWorkbook hwb, HashMap cadreMap, HashMap storeProductMap, String startDate, String endDate){
        
        HSSFSheet sheet3 = hwb.createSheet("幹部開酒分析表");
        HSSFRow row3 = sheet3.createRow(0);
        HSSFCell cell3 = row3.createCell(0);
        cell3.setCellValue("日期："+startDate+"~"+endDate);
        row3 = sheet3.createRow(1);
        cell3 = row3.createCell(0);
        cell3.setCellValue("NO");
        cell3.setCellStyle(getCellStyle(hwb));
        row3.createCell(1).setCellValue("幹部名稱");
        row3.getCell(1).setCellStyle(getCellStyle(hwb));
        int c = 1;
        Set productSet = storeProductMap.keySet();        
        Iterator productIter = productSet.iterator();
        String productKey;
        int no = 1; 
        while (productIter.hasNext()){
            productKey =  (String) productIter.next();
            c = c + 1;
            row3 = sheet3.getRow(1);
            row3.createCell(c).setCellValue(productKey);
            row3.getCell(c).setCellStyle(getCellStyle(hwb));
            Set cadreSet = cadreMap.keySet();        
            Iterator cadreIter = cadreSet.iterator();
            String cadreKey;
            HashMap cadreProdMap;
            no = 1;                                
            while (cadreIter.hasNext()){
                cadreKey =  (String) cadreIter.next();                
                no = no + 1;                                    
                row3 = sheet3.getRow(no)==null?sheet3.createRow(no):sheet3.getRow(no);
                row3.createCell(0).setCellValue(String.valueOf(no-1));                
                row3.createCell(1).setCellValue(cadreKey);                
                cadreProdMap = (HashMap)cadreMap.get(cadreKey);
                if(cadreProdMap.containsKey(productKey)){
                    row3.createCell(c).setCellValue((Double)cadreProdMap.get(productKey));                    
                }
            }
        }
        row3 = sheet3.getRow(1);
        row3.createCell(c+1).setCellValue("小計");
        row3.getCell(c+1).setCellStyle(getSubSummaryStyle(hwb));
        String startCell, endCell;
        for(int i=2;i<=no;i++){
            startCell = getCellName(i,2);
            endCell = getCellName(i,c);                    
            row3 = sheet3.getRow(i);
            cell3 = row3.createCell(c+1);
            cell3.setCellFormula("SUM("+startCell+":"+endCell+")");
            cell3.setCellStyle(getSubSummaryStyle(hwb));
        }
        row3 = sheet3.createRow(no+1);
        cell3 = row3.createCell(c+1);
        startCell = getCellName(2,c+1);
        endCell = getCellName(no,c+1);
        cell3.setCellFormula("SUM("+startCell+":"+endCell+")");
        cell3.setCellStyle(getSummaryStyle(hwb));
        mergeCell(hwb, sheet3, no+1, no+1, 0, c);
        cell3 = row3.getCell(0);
        cell3.setCellValue("總計");
        HSSFCellStyle totalStyle = getSummaryStyle(hwb);
        totalStyle = setAlign(totalStyle,2);
        cell3.setCellStyle(totalStyle);
    }    
    
    //產生某段期間的週會記錄
    void genMeetingSheet(HSSFWorkbook hwb, String startDate, String endDate, String storeName){
        final String AP_NAME = "diageo";
        final int MT_NO = 1000256;      //會議編號
        final int MT_AREA = 1000257;    //地區
        final int MT_STORE = 1000057;   //店名
        final int MT_MEMBER = 1000258;  //出席人員
        final int MT_START = 1000259;   //週起迄日
        final int MT_END = 1000260;
        final int MT_RECORD = 1000261;  //會議記錄
        final int MT_DATE = 1000262;  //開會日期
        final int CONSUME_TYPE = 1000263;   //消費型態
        final int CONSUME_STAT = 1000264;   //生意狀況
        final int PROMOTE_STAT = 1000265;   //促銷狀況
        final int PROMOTE_WAY = 1000266;   //促銷方式
        final int COMP_WAY = 1000267;   //競品促銷方式
        final int COMP_GIFT = 1000268;   //競品贈品
        HashMap userMap = getUserMap();
        BDBWorker worker = new BDBWorker(AP_NAME);
        try {
            HSSFSheet sheet = null;
            HSSFRow row = null;
            HSSFCell cell = null;
            SDBQuery q = new SDBQueryFull(worker);
            SDBNode node;
            q.go(MT_NO);            
            q.filterRange(MT_START, endDate, startDate);
            q.filter(MT_STORE, storeName);
            while((node=q.next())!=null){
                sheet = hwb.createSheet("週會記錄("+q.dip(MT_START).replace("/", ".")+"~"+q.dip(MT_END).replace("/", ".")+")");
                HSSFRichTextString ts= new HSSFRichTextString(q.dip(MT_AREA)+"PG會議記錄"
                        + "   (by "+getUserName(userMap, q.dip(MT_RECORD))+")");
                HSSFFont font = hwb.createFont();
                font.setFontHeightInPoints((short)14);
                font.setBold(true);
                HSSFFont font1 = hwb.createFont();
                font1.setFontHeightInPoints((short)10);
                font1.setBold(true);
                font1.setItalic(true);
                font1.setColor(HSSFColor.HSSFColorPredefined.BLUE.getIndex());
                //ts.applyFont(0, ts.length()-12, font);    //如自尾端起算的字元固定時
                //ts.applyFont(ts.length()-12,ts.length(),font1);
                ts.applyFont(0, 11, font);
                ts.applyFont(12,ts.length()-1,font1);                
                sheet.createRow(0).createCell(0).setCellValue(ts);
                HSSFCellStyle titleStyle = hwb.createCellStyle();
                titleStyle = setAlign(titleStyle, 0);
                sheet.getRow(0).getCell(0).setCellStyle(titleStyle);                
                sheet.addMergedRegion(new CellRangeAddress(0, 0, 0, 1));
                sheet.setColumnWidth(0, 4000);
                sheet.setColumnWidth(1, 18000);                
                sheet.setDefaultColumnStyle(0, getTextStyle(hwb));
                sheet.setDefaultColumnStyle(1, getTextStyle(hwb));                               
                sheet.createRow(1).createCell(0).setCellValue("店名："+q.dip(MT_STORE));                
                sheet.addMergedRegion(new CellRangeAddress(1, 1, 0, 1));
                sheet.getRow(1).setHeight((short)500);
                String members = q.dipAll(MT_MEMBER);
                String memName = "";
                for(int i=0; i<members.split(", ").length;i++){
                    memName = getUserName(userMap, members.split(", ")[i]);
                    members = members.replace(members.split(", ")[i], memName);
                }                
                sheet.createRow(2).createCell(0).setCellValue("出席人員："+members);
                sheet.addMergedRegion(new CellRangeAddress(2, 2, 0, 1));
                sheet.createRow(3).createCell(0).setCellValue("日期："+q.dip(MT_START)+" ~ "+q.dip(MT_END));
                sheet.addMergedRegion(new CellRangeAddress(3, 3, 0, 1));
                sheet.createRow(4).createCell(0).setCellValue("開會日期："+q.dip(MT_DATE));
                sheet.addMergedRegion(new CellRangeAddress(4, 4, 0, 1));
                sheet.createRow(5).createCell(0).setCellValue("會議摘要：");                
                sheet.addMergedRegion(new CellRangeAddress(5, 5, 0, 1));
                sheet.getRow(5).setHeight((short)500);
                sheet.createRow(6).createCell(0).setCellValue("消費型態");
                sheet.getRow(6).createCell(1).setCellValue("\n"+q.dip(CONSUME_TYPE)+"\n");
                sheet.createRow(7).createCell(0).setCellValue("生意狀況");
                sheet.getRow(7).createCell(1).setCellValue("\n"+q.dip(CONSUME_STAT)+"\n");
                sheet.createRow(8).createCell(0).setCellValue("促銷狀況");
                sheet.getRow(8).createCell(1).setCellValue("\n"+q.dip(PROMOTE_STAT)+"\n");
                sheet.createRow(9).createCell(0).setCellValue("促銷方式");
                sheet.getRow(9).createCell(1).setCellValue("\n"+q.dip(PROMOTE_WAY)+"\n");
                sheet.createRow(10).createCell(0).setCellValue("競品促銷方式");
                sheet.getRow(10).createCell(1).setCellValue("\n"+q.dip(COMP_WAY)+"\n");
                sheet.createRow(11).createCell(0).setCellValue("競品贈品");
                sheet.getRow(11).createCell(1).setCellValue("\n"+q.dip(COMP_GIFT)+"\n");                
            }
        } finally {
            worker.commit();
        }
        
    }
    
    HashMap getUserMap(){
        final String AP_NAME = "diageo";
        final int USER_ID = DConst.USER_USERID_EMAIL;
        final int USER_NAME = DConst.USER_NAME;
        BDBWorker worker = new BDBWorker(AP_NAME);
        HashMap userMap = new HashMap();
        try {
            SDBQuery userq = new SDBQueryFull(worker);
            SDBNode node;
            userq.go(USER_ID);
            while((node=userq.next())!=null){
                if(!userMap.containsKey(userq.dip(USER_ID))){
                    userMap.put(userq.dip(USER_ID), userq.dip(USER_NAME));            
                }
            }
        } finally {
            worker.commit();
        }
        return userMap;
    }
    
    String getUserName(HashMap userMap, String userId){
        String userName = "";
        if(userMap.containsKey(userId)){
            userName = userMap.get(userId).toString();
        }
        return userName;
    }
    
